import javafx.application.Application;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.control.TextField;
import javafx.scene.layout.BorderPane;
import javafx.scene.layout.GridPane;
import javafx.scene.layout.HBox;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

public class GridBorderPaneExample extends Application {
    @Override
    public void start(Stage primaryStage) {
        // 1. GridPane — grid layout (rows and columns)
        System.out.println("=== GridPane ===");
        GridPane grid = new GridPane();
        grid.setHgap(10);
        grid.setVgap(10);
        grid.setPadding(new Insets(20));

        // Adding nodes with row and column indices
        Label nameLabel = new Label("Name:");
        TextField nameField = new TextField();

        Label emailLabel = new Label("Email:");
        TextField emailField = new TextField();

        Label phoneLabel = new Label("Phone:");
        TextField phoneField = new TextField();

        // Add to GridPane (row, column)
        grid.add(nameLabel, 0, 0);
        grid.add(nameField, 1, 0);
        grid.add(emailLabel, 0, 1);
        grid.add(emailField, 1, 1);
        grid.add(phoneLabel, 0, 2);
        grid.add(phoneField, 1, 2);

        Button submitBtn = new Button("Submit");
        grid.add(submitBtn, 1, 3);

        // Column constraints
        grid.setColumnSpan(submitBtn, 1);
        GridPane.setHalignment(submitBtn, javafx.geometry.HPos.RIGHT);

        // 2. BorderPane — top, bottom, left, center, right
        System.out.println("=== BorderPane ===");
        BorderPane border = new BorderPane();
        border.setPadding(new Insets(10));

        // Top
        Label header = new Label("Application Header");
        header.setStyle("-fx-font-size: 24px; -fx-font-weight: bold;");
        HBox topBox = new HBox(header);
        topBox.setAlignment(Pos.CENTER);
        topBox.setStyle("-fx-background-color: #e0e0e0; -fx-padding: 10px;");
        border.setTop(topBox);

        // Center
        VBox centerBox = new VBox(10);
        centerBox.setAlignment(Pos.CENTER);
        centerBox.getChildren().addAll(
            new Label("Main Content Area"),
            new Button("Click Me"),
            new Label("More content here...")
        );
        border.setCenter(centerBox);

        // Bottom
        HBox bottomBox = new HBox(10);
        bottomBox.setAlignment(Pos.CENTER);
        bottomBox.setStyle("-fx-background-color: #f0f0f0; -fx-padding: 10px;");
        bottomBox.getChildren().addAll(
            new Button("OK"),
            new Button("Cancel"),
            new Button("Apply")
        );
        border.setBottom(bottomBox);

        // Left
        VBox leftBox = new VBox(10);
        leftBox.setAlignment(Pos.CENTER);
        leftBox.setStyle("-fx-background-color: #f5f5f5; -fx-padding: 10px;");
        leftBox.getChildren().addAll(
            new Button("Home"),
            new Button("About"),
            new Button("Contact")
        );
        border.setLeft(leftBox);

        // Right
        VBox rightBox = new VBox(10);
        rightBox.setAlignment(Pos.CENTER);
        rightBox.setStyle("-fx-background-color: #f5f5f5; -fx-padding: 10px;");
        rightBox.getChildren().addAll(
            new Label("Sidebar"),
            new Button("Settings"),
            new Button("Help")
        );
        border.setRight(rightBox);

        // 3. Combining both layouts
        System.out.println("=== Combined Layout ===");
        VBox combined = new VBox(20);
        combined.setPadding(new Insets(20));
        combined.setAlignment(Pos.CENTER);

        Label gridLabel = new Label("GridPane Example:");
        gridLabel.setStyle("-fx-font-size: 18px; -fx-font-weight: bold;");

        Label borderLabel = new Label("BorderPane Example:");
        borderLabel.setStyle("-fx-font-size: 18px; -fx-font-weight: bold;");

        // GridPane with reduced size for display
        GridPane smallGrid = new GridPane();
        smallGrid.setHgap(10);
        smallGrid.setVgap(10);
        smallGrid.add(new Label("A"), 0, 0);
        smallGrid.add(new Label("B"), 1, 0);
        smallGrid.add(new Label("C"), 0, 1);
        smallGrid.add(new Label("D"), 1, 1);

        BorderPane smallBorder = new BorderPane();
        smallBorder.setTop(new Label("Top"));
        smallBorder.setCenter(new Label("Center"));
        smallBorder.setBottom(new Label("Bottom"));

        combined.getChildren().addAll(
            gridLabel, smallGrid,
            borderLabel, smallBorder
        );

        Scene scene = new Scene(combined, 800, 700);

        primaryStage.setTitle("GridPane & BorderPane");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}

