import javafx.application.Application;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.layout.GridPane;
import javafx.stage.Stage;

public class Test extends Application {
    @Override
    public void start(Stage primaryStage) {
        GridPane grid = new GridPane();
        grid.setHgap(10);
        grid.setVgap(10);

        Label label = new Label("Name:");
        Button button = new Button("Click");

        // Forgetting to specify row and column
        grid.getChildren().add(label);  // No position!
        grid.getChildren().add(button); // No position!

        Scene scene = new Scene(grid, 300, 200);
        primaryStage.setScene(scene);
        primaryStage.show();
    }
}

phase2.explanation:
When you use add() without specifying row/column, both nodes go to (0,0) and overlap!

FIX: Use add(node, column, row):
grid.add(label, 0, 0);
grid.add(button, 1, 0);

Or set row/column indices:
GridPane.setRowIndex(label, 0);
GridPane.setColumnIndex(label, 0);

Always specify positions in GridPane!

