import javafx.application.Application;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.layout.BorderPane;
import javafx.scene.layout.GridPane;
import javafx.scene.layout.HBox;
import javafx.stage.Stage;

public class Dashboard extends Application {
    @Override
    public void start(Stage primaryStage) {
        BorderPane border = new BorderPane();
        border.setPadding(new Insets(10));

        // Top
        Label header = new Label("My Dashboard");
        header.setStyle("-fx-font-size: 24px; -fx-font-weight: bold;");
        HBox topBox = new HBox(header);
        topBox.setAlignment(Pos.CENTER);
        topBox.setStyle("-fx-background-color: #e0e0e0; -fx-padding: 10px;");
        border.setTop(topBox);

        // Center
        GridPane grid = new GridPane();
        grid.setHgap(20);
        grid.setVgap(10);
        grid.setPadding(new Insets(20));
        grid.setAlignment(Pos.CENTER);

        grid.add(new Label("Product"), 0, 0);
        grid.add(new Label("Price"), 1, 0);
        grid.add(new Label("Laptop"), 0, 1);
        grid.add(new Label("$1200"), 1, 1);
        grid.add(new Label("Phone"), 0, 2);
        grid.add(new Label("$800"), 1, 2);

        border.setCenter(grid);

        // Bottom
        HBox bottomBox = new HBox(10);
        bottomBox.setAlignment(Pos.CENTER);
        bottomBox.setStyle("-fx-padding: 10px; -fx-background-color: #f0f0f0;");
        bottomBox.getChildren().addAll(
            new Button("Add"),
            new Button("Delete"),
            new Button("Update")
        );
        border.setBottom(bottomBox);

        Scene scene = new Scene(border, 500, 400);
        primaryStage.setTitle("Dashboard");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}
